svg.script:
const BASE_URL = "embedded";
const ANCHOR_JSON = "embedded";
const SVG_NS = "http://www.w3.org/2000/svg";
const PART_STORAGE_KEY = "hamster-working-typing-composite-v1-part-transforms";
const BODY_BASE_D = "M163.75 200 C100.24 200 54.75 251 54.75 322 C54.75 375.7 99.08 412 170.72 412 C269.61 412 303.48 385.22 303.48 322 C303.48 244.61 254.13 200 163.75 200Z";
const VIEW_W = 374;
const TOP_CHAIN = ["A", "L", "C", "D", "E", "R", "G"];
const BASE_HEAD = {
  cheekD: "M65 153 C97 159 136 168 172 154 C181 150 193 147 202 154 C238 168 277 159 309 153 C331 178 336 221 303 246 C270 268 104 268 71 246 C38 221 43 178 65 153Z",
  headCapD: "M64 153 C64 88 116 48 187 48 C258 48 310 88 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z",
  leftCreaseD: "M62 238 C70 250 84 256 100 256",
  rightCreaseD: "M312 238 C304 250 290 256 274 256"
};
const RIGHT_HEAD_CAP_D = "M64 153 C66.12 89.55 117.55 49.81 187 48 C267.24 48 328.48 88 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z";
const LEFT_HEAD_CAP_D = "M64 153 C45.52 88 106.76 48 187 48 C256.45 49.81 307.88 89.55 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z";
const FRONT_TAIL = [
  [331, 178, 336, 221, 303, 246],
  [270, 268, 104, 268, 71, 246],
  [38, 221, 43, 178, 65, 153]
];
const LEFT_TAIL = [
  [320.06, 180.73, 321.87, 218.27, 303, 246],
  [270, 268, 104, 268, 71, 246],
  [35.12, 221, 40.60, 178, 65, 153]
];
const RIGHT_TAIL = [
  [333.40, 178.00, 338.88, 221.00, 303, 246],
  [270, 268, 104, 268, 71, 246],
  [52.13, 218.27, 53.94, 180.73, 65, 153]
];
const PITCH_UP = {
  axis: -25.5,
  lower: 3.6,
  faceDy: -21.5,
  faceSy: 0.93,
  blushDy: -22.41,
  earDy: 12,
  tuftDy: 12
};
const PITCH_DOWN = {
  axis: 26,
  lower: -7.9,
  faceDy: 24.5,
  faceSy: 1,
  blushDy: 24.5,
  earDy: -10,
  tuftDy: -2
};
const LEFT_ARM_PATCH = {
  href: "data:image/png;base64,",
  x: 83.7,
  y: 220.4,
  width: 70.4,
  height: 101.8
};
const PART_META = {
  rightArm: { pivot: { x: 266, y: 292 } },
  leftArm: { pivot: { x: 121, y: 270 } },
  leftFoot: { pivot: { x: 75, y: 370 } },
  rightFoot: { pivot: { x: 268, y: 374 } }
};
const PART_DEFAULTS = {
  rightArm: { x: -8, y: 30, scale: 1, rotate: 0 },
  leftArm: { x: -47.5, y: 18.5, scale: 1, rotate: -0.5 },
  leftFoot: { x: -18.5, y: 19, scale: 0.65, rotate: 8 },
  rightFoot: { x: 4.5, y: 13, scale: 0.68, rotate: -8 }
};
const $ = (id) => document.getElementById(id);
const TAU = Math.PI * 2;
const HEAD_FRAME_PIVOT = { x: 187, y: 246 };
const HEAD_FRAME_FIXED_SCALE = 0.93;
const HEAD_KEY_ORDER = ["start", "middle", "end"];
const HEAD_SYNC_DURATION = 4200;
const HEAD_LOOK_PERSON_HOLD = { start: 0.66, end: 0.86 };
const HEAD_KEY_LABELS = {
  start: "屏幕左看",
  middle: "屏幕右看",
  end: "看人帧"
};
const HEAD_KEY_DEFAULTS = {
  start: { yaw: -78, pitch: 70, angle: -3 },
  middle: { yaw: -46, pitch: 70, angle: -3 },
  end: { yaw: -50, pitch: 42, angle: -3 }
};
const HAND_TYPING_POSES = {
  a: {
    label: "姿势 1",
    left: { angle: 3.5, pivotX: 119, pivotY: 259 },
    right: { angle: 7, pivotX: 280.5, pivotY: 262 }
  },
  b: {
    label: "姿势 2",
    left: { angle: 17, pivotX: 119, pivotY: 259 },
    right: { angle: -8, pivotX: 280.5, pivotY: 262 }
  }
};
const HAND_ROTATION_DEFAULTS = HAND_TYPING_POSES.a;
const BAKED_RAW_ANCHORS = {"source":"../../master/hamster-flat-layered-v15-clear-lens.svg","method":"side-45-face-anchor-v1-bf-eye-decoupled-final-display-coordinate-contract","note":"Anchors are final display coordinates. B/F are the visual eye-center anchors; L/R are the face-top curve low anchors; H/T/EL/ER are head motion reference anchors. Future face paths must pass through the relevant path anchors; marker coordinates, path anchor coordinates, and exported SVG coordinates must match.","glassesHiddenByDefault":true,"topCurveAnchors":["A","L","C","D","E","R","G"],"topCurveLowAnchors":["L","R"],"eyeCenterAnchors":["B","F"],"headMotionAnchors":["H","T","EL","ER"],"topSegments":[{"id":"AL","from":"A","to":"L"},{"id":"LC","from":"L","to":"C"},{"id":"CD","from":"C","to":"D"},{"id":"DE","from":"D","to":"E"},{"id":"ER","from":"E","to":"R"},{"id":"RG","from":"R","to":"G"}],"groups":[{"id":"top","label":"黄白顶线","anchors":[{"id":"A","label":"左边界","role":"face-top-left-edge","x":65,"y":153},{"id":"L","label":"左弧低点","role":"left-face-top-curve-low","x":137.77,"y":162.56},{"id":"C","label":"鼻梁左","role":"left-bridge-end","x":171.37,"y":154.02},{"id":"D","label":"鼻梁峰","role":"bridge-peak","x":189.69,"y":147.65},{"id":"E","label":"鼻梁右","role":"right-bridge-end","x":210.43,"y":157.48},{"id":"R","label":"右弧低点","role":"right-face-top-curve-low","x":240.66,"y":162.63},{"id":"G","label":"右边界","role":"face-top-right-edge","x":309,"y":153}]},{"id":"features","label":"五官绑定","anchors":[{"id":"B","label":"左眼中心","role":"left-eye-center","x":138,"y":157},{"id":"F","label":"右眼中心","role":"right-eye-center","x":237,"y":157},{"id":"N","label":"鼻中心","role":"nose-center","x":187,"y":170},{"id":"J","label":"鼻下","role":"nose-mouth-joint","x":187,"y":177},{"id":"ML","label":"嘴左端","role":"mouth-left-end","x":163,"y":192},{"id":"MR","label":"嘴右端","role":"mouth-right-end","x":211,"y":192},{"id":"BL","label":"左腮红","role":"left-blush-center","x":92,"y":185},{"id":"BR","label":"右腮红","role":"right-blush-center","x":281,"y":185}]},{"id":"head_motion","label":"头部运动参考","anchors":[{"id":"H","label":"头顶","role":"head-top","x":187,"y":48},{"id":"T","label":"呆毛","role":"tuft-point","x":203,"y":16},{"id":"EL","label":"左耳","role":"left-ear","x":101,"y":73},{"id":"ER","label":"右耳","role":"right-ear","x":286,"y":73}]},{"id":"creases","label":"腮下阴影","anchors":[{"id":"LS","label":"左腮影起","role":"left-crease-start","x":62,"y":238},{"id":"LC1","label":"左腮影控1","role":"left-crease-control-1","x":70,"y":250},{"id":"LC2","label":"左腮影控2","role":"left-crease-control-2","x":84,"y":256},{"id":"LE","label":"左腮影止","role":"left-crease-end","x":100,"y":256},{"id":"RS","label":"右腮影起","role":"right-crease-start","x":312,"y":238},{"id":"RC1","label":"右腮影控1","role":"right-crease-control-1","x":304,"y":250},{"id":"RC2","label":"右腮影控2","role":"right-crease-control-2","x":290,"y":256},{"id":"RE","label":"右腮影止","role":"right-crease-end","x":274,"y":256}]},{"id":"attachments","label":"耳朵呆毛","anchors":[{"id":"ELR","label":"左耳根","role":"left-ear-root","x":88,"y":102},{"id":"ELC","label":"左耳心","role":"left-ear-center","x":101,"y":73},{"id":"ELI","label":"左内耳","role":"left-inner-ear-center","x":101,"y":73},{"id":"ERR","label":"右耳根","role":"right-ear-root","x":274,"y":102},{"id":"ERC","label":"右耳心","role":"right-ear-center","x":286,"y":73},{"id":"ERI","label":"右内耳","role":"right-inner-ear-center","x":286,"y":73},{"id":"TLR","label":"左呆毛根","role":"left-tuft-root","x":182,"y":49},{"id":"TLC","label":"左呆毛控","role":"left-tuft-control","x":184,"y":35},{"id":"TLT","label":"左呆毛尖","role":"left-tuft-tip","x":192,"y":15},{"id":"TRR","label":"右呆毛根","role":"right-tuft-root","x":200,"y":50},{"id":"TRC","label":"右呆毛控","role":"right-tuft-control","x":203,"y":34},{"id":"TRT","label":"右呆毛尖","role":"right-tuft-tip","x":214,"y":16}]}]};
const DUMMY_CLASS_LIST = { toggle() {} };
const DUMMY_EL = {
  style: {},
  classList: DUMMY_CLASS_LIST,
  setAttribute() {},
  removeAttribute() {},
  querySelector() { return null; },
  querySelectorAll() { return []; }
};
const valueControl = (value) => ({
  value: String(value),
  checked: Boolean(value),
  addEventListener() {},
  classList: DUMMY_CLASS_LIST,
  textContent: ""
});
const outputNode = () => ({ textContent: "" });
const controls = {
  headYaw: valueControl(-78),
  headPitch: valueControl(70),
  headAngle: valueControl(-3),
  playing: valueControl(false),
  phase: valueControl(0),
  tapAmp: valueControl(7),
  leftAmp: valueControl(3.5),
  bodyBreath: valueControl(3),
  bodyBackBulge: valueControl(25.5),
  patchX: valueControl(7.5),
  patchY: valueControl(0),
  patchScale: valueControl(1),
  laptopX: valueControl(-61),
  laptopY: valueControl(129.5),
  laptopScale: valueControl(0.31),
  glowPower: valueControl(0.9),
  handPreviewMs: valueControl(120),
  handLookMs: valueControl(220),
  showOriginalLimbs: valueControl(false),
  showChecker: valueControl(false),
  showFullSource: valueControl(false),
  showClipGuides: valueControl(false),
  showLaptop: valueControl(true),
  showAtmosphere: valueControl(true)
};
const partControls = {
  x: valueControl(0),
  y: valueControl(0),
  scale: valueControl(1),
  rotate: valueControl(0)
};
const handControls = {
  leftHandAngle: valueControl(3.5),
  rightHandAngle: valueControl(7),
  leftPivotX: valueControl(119),
  leftPivotY: valueControl(259),
  rightPivotX: valueControl(280.5),
  rightPivotY: valueControl(262)
};
const outputs = {
  headYaw: outputNode(),
  headPitch: outputNode(),
  headAngle: outputNode(),
  phase: outputNode(),
  tapAmp: outputNode(),
  leftAmp: outputNode(),
  bodyBreath: outputNode(),
  bodyBackBulge: outputNode(),
  patchX: outputNode(),
  patchY: outputNode(),
  patchScale: outputNode(),
  laptopX: outputNode(),
  laptopY: outputNode(),
  laptopScale: outputNode(),
  glowPower: outputNode(),
  handPreviewMs: outputNode(),
  handLookMs: outputNode(),
  partX: outputNode(),
  partY: outputNode(),
  partScale: outputNode(),
  partRotate: outputNode(),
  leftHandAngle: outputNode(),
  rightHandAngle: outputNode(),
  leftPivotX: outputNode(),
  leftPivotY: outputNode(),
  rightPivotX: outputNode(),
  rightPivotY: outputNode()
};
const elems = {
  baseMount: DUMMY_EL,
  stage: DUMMY_EL,
  compositeSvg: document.documentElement,
  underBodyPatchLayer: $("underBodyPatchLayer"),
  limbPatchLayer: $("limbPatchLayer"),
  leftArm: null,
  rightArm: $("rightTypingArmPatch"),
  leftFoot: $("leftFootPatch"),
  rightFoot: $("rightFootPatch"),
  leftArmGuide: DUMMY_EL,
  rightArmGuide: DUMMY_EL,
  leftFootGuide: DUMMY_EL,
  rightFootGuide: DUMMY_EL,
  sourceGhost: DUMMY_EL,
  clipGuides: DUMMY_EL,
  handPivotGuides: DUMMY_EL,
  laptopMapped: $("laptopMappedLayer"),
  laptop: $("laptopGroup"),
  keyboardTap: $("keyboardTap"),
  atmosphere: $("workingAtmosphereLayer"),
  screenGlow: $("screenGlowLayer"),
  screenGlowBeam: $("screenGlowBeam"),
  screenGlowHalo: $("screenGlowHalo"),
  faceGlowWash: $("faceGlowWash"),
  screenEdgeGlow: $("screenEdgeGlow"),
  headFrameLayer: null,
  headKeyReadout: outputNode(),
  handRotationReadout: outputNode(),
  leftHandPivotGuide: DUMMY_EL,
  rightHandPivotGuide: DUMMY_EL,
  leftHandPivotCircle: DUMMY_EL,
  rightHandPivotCircle: DUMMY_EL,
  leftHandPivotCrossH: DUMMY_EL,
  leftHandPivotCrossV: DUMMY_EL,
  rightHandPivotCrossH: DUMMY_EL,
  rightHandPivotCrossV: DUMMY_EL,
  status: outputNode()
};

let baseSvg = null;
let rawAnchors = {};
let phase = 0;
let lastTime = 0;
let rafId = 0;
let activePart = "leftArm";
let activeHeadKey = "start";
const headKeyframes = structuredClone(HEAD_KEY_DEFAULTS);
let headLook = headKeyframes[activeHeadKey];
let headPreviewMeta = { from: activeHeadKey, to: activeHeadKey, local: 0, progress: 0 };
let previewingHead = false;
let headPreviewStart = 0;
let previewingHands = false;
const partTransforms = normalizePartTransforms(PART_DEFAULTS);

init();

function init() {
  baseSvg = document.documentElement;
  rawAnchors = flattenAnchors(BAKED_RAW_ANCHORS);
  elems.leftArm = $("leftTypingArmPatch");
  applyBaseContract();
  prepareWorkingBlushClip();
  ensureHeadFrameLayer();
  controls.playing.checked = false;
  controls.phase.value = 0;
  phase = 0;
  previewingHands = true;
  previewingHead = true;
  headPreviewStart = performance.now();
  lastTime = 0;
  render(performance.now());
}

function scheduleRender() {
  if (rafId) return;
  rafId = requestAnimationFrame((now) => {
    rafId = 0;
    render(now);
  });
}

function applyBaseContract() {
  if (!baseSvg) return;
  baseSvg.querySelector("#hamster-flat-master-v11")?.removeAttribute("filter");
  toggleOriginalLimbs();
}

function installLeftArmUnderFaceLayer() {
  if (!baseSvg) return;
  const root = baseSvg.querySelector("#hamster-flat-master-v11");
  if (!root) return;

  root.querySelector("#leftTypingArmPatch")?.remove();
  const layer = document.createElementNS(SVG_NS, "g");
  layer.setAttribute("id", "leftTypingArmPatch");
  layer.setAttribute("data-layer", "left-arm-under-face");
  layer.setAttribute("filter", "url(#patchShadow)");

  const image = document.createElementNS(SVG_NS, "image");
  image.setAttribute("href", LEFT_ARM_PATCH.href);
  image.setAttribute("x", fmt(LEFT_ARM_PATCH.x));
  image.setAttribute("y", fmt(LEFT_ARM_PATCH.y));
  image.setAttribute("width", fmt(LEFT_ARM_PATCH.width));
  image.setAttribute("height", fmt(LEFT_ARM_PATCH.height));
  layer.append(image);

  const insertionPoint = root.querySelector("#ears-layer") || root.querySelector("#head-tufts") || root.querySelector("#head-layer");
  root.insertBefore(layer, insertionPoint);
  elems.leftArm = layer;
}

function flattenAnchors(data) {
  const points = {};
  (data.groups || []).forEach((group) => {
    (group.anchors || []).forEach((anchor) => {
      points[anchor.id] = { x: Number(anchor.x), y: Number(anchor.y), label: anchor.label || anchor.id };
    });
  });
  return points;
}

function ensureDefs() {
  let defs = baseSvg.querySelector("defs");
  if (!defs) {
    defs = document.createElementNS(SVG_NS, "defs");
    baseSvg.insertBefore(defs, baseSvg.firstElementChild);
  }
  return defs;
}

function prepareWorkingBlushClip() {
  if (!baseSvg) return;
  const blushes = baseSvg.querySelector("#blushes");
  const headLayer = baseSvg.querySelector("#head-layer");
  if (!blushes || !headLayer || baseSvg.querySelector("#idle-look-blush-clip-wrapper")) return;

  const oldWrapper = baseSvg.querySelector("#body-left-blush-clip-wrapper");
  const clip = document.createElementNS(SVG_NS, "clipPath");
  clip.setAttribute("id", "idle-look-blush-clip");
  clip.setAttribute("clipPathUnits", "userSpaceOnUse");
  const clipPath = document.createElementNS(SVG_NS, "path");
  clipPath.setAttribute("id", "idle-look-blush-clip-path");
  clip.appendChild(clipPath);
  ensureDefs().appendChild(clip);

  const wrapper = document.createElementNS(SVG_NS, "g");
  wrapper.setAttribute("id", "idle-look-blush-clip-wrapper");
  wrapper.setAttribute("data-layer", "working-idle-look-blush-clip-host");
  wrapper.setAttribute("clip-path", "url(#idle-look-blush-clip)");

  const transformGroup = document.createElementNS(SVG_NS, "g");
  transformGroup.setAttribute("id", "idle-look-blush-transform");
  transformGroup.appendChild(blushes);
  wrapper.appendChild(transformGroup);
  headLayer.appendChild(wrapper);
  oldWrapper?.remove();
}

function ensureHeadFrameLayer() {
  if (!baseSvg) return;
  const root = baseSvg.querySelector("#hamster-flat-master-v11");
  if (!root) return;

  let layer = root.querySelector("#working-head-motion-layer");
  if (layer) {
    elems.headFrameLayer = layer;
    return;
  }

  const selectors = [
    "#ears-layer",
    "#head-tufts",
    "#head-layer",
    "#face-layer"
  ];
  const nodes = selectors
    .map((selector) => root.querySelector(selector))
    .filter(Boolean);
  if (!nodes.length) return;

  layer = document.createElementNS(SVG_NS, "g");
  layer.setAttribute("id", "working-head-motion-layer");
  layer.setAttribute("data-layer", "working-head-keyframe-motion");
  root.insertBefore(layer, nodes[0]);
  nodes.forEach((node) => layer.append(node));
  elems.headFrameLayer = layer;
}

function applyHeadFrameTransform() {
  if (!elems.headFrameLayer) return;
  const angle = headLook.angle ?? headKeyframes[activeHeadKey].angle;
  elems.headFrameLayer.setAttribute(
    "transform",
    `translate(${HEAD_FRAME_PIVOT.x} ${HEAD_FRAME_PIVOT.y}) rotate(${fmt(angle)}) scale(${fmt(HEAD_FRAME_FIXED_SCALE)}) translate(-${HEAD_FRAME_PIVOT.x} -${HEAD_FRAME_PIVOT.y})`
  );
}

function toggleOriginalLimbs() {
  if (!baseSvg) return;
  const display = controls.showOriginalLimbs.checked ? "" : "none";
  ["#hands-layer", "#right-hand-front-layer", "#feet-layer"].forEach((selector) => {
    const node = baseSvg.querySelector(selector);
    if (node) node.style.display = display;
  });
}

function render(now = 0) {
  if (previewingHands) {
    const dt = lastTime ? Math.min(80, now - lastTime) : 16;
    phase = (phase + dt / handCycleMs(now)) % 1;
    controls.phase.value = Math.round(phase * 100);
  } else if (controls.playing.checked) {
    const dt = lastTime ? Math.min(80, now - lastTime) : 16;
    phase = (phase + dt / 1450) % 1;
    controls.phase.value = Math.round(phase * 100);
  } else {
    phase = num("phase") / 100;
  }
  lastTime = now;

  const oldTypingMotion = controls.playing.checked && !previewingHands;
  const oldTypingPhase = oldTypingMotion ? phase : 0;
  const rightBeat = oldTypingMotion ? easePulse(Math.max(0, Math.sin(TAU * oldTypingPhase))) : 0;
  const leftBeat = oldTypingMotion ? easePulse(Math.max(0, Math.sin(TAU * oldTypingPhase + Math.PI))) : 0;
  const breath = Math.sin(TAU * oldTypingPhase - Math.PI / 5);
  const patchScale = num("patchScale");
  const patchX = num("patchX");
  const patchY = num("patchY");
  const breathAmp = num("bodyBreath");

  const baseRoot = baseSvg?.querySelector("#hamster-flat-master-v11");
  if (baseRoot) {
    applyBodyShape();
    renderHeadLook(now);
    const sx = 1 + breath * breathAmp * 0.0007;
    const sy = 1 + breath * breathAmp * 0.00045;
    const y = -breath * breathAmp * 0.12;
    baseRoot.setAttribute("transform", `translate(187 275) scale(${fmt(sx)} ${fmt(sy)}) translate(-187 -275) translate(0 ${fmt(y)})`);
    applyHeadFrameTransform();
  }

  const patchTransform = `translate(187 260) scale(${fmt(patchScale)}) translate(-187 -260) translate(${fmt(patchX)} ${fmt(patchY)})`;
  elems.underBodyPatchLayer.setAttribute("transform", patchTransform);
  elems.limbPatchLayer.setAttribute("transform", patchTransform);
  const handPose = renderedHandPose();

  const rightDy = num("tapAmp") * rightBeat;
  const rightDx = -1.6 + rightBeat * 2.7;
  const rightRot = -2.6 + rightBeat * 4.8;
  const rightArmTransform = withHandRotation(
    "right",
    withPartTransform("rightArm", `translate(237 306) rotate(${fmt(rightRot)}) translate(-237 -306) translate(${fmt(rightDx)} ${fmt(rightDy)})`),
    handPose
  );
  elems.rightArm.setAttribute(
    "transform",
    rightArmTransform
  );
  elems.rightArmGuide.setAttribute("transform", `${patchTransform} ${rightArmTransform}`);

  const leftDy = num("leftAmp") * leftBeat;
  const leftDx = leftBeat * 1.1;
  const leftRot = -1.6 - leftBeat * 2.6;
  const leftArmTransform = `${patchTransform} ${withHandRotation(
    "left",
    withPartTransform("leftArm", `translate(124 296) rotate(${fmt(leftRot)}) translate(-124 -296) translate(${fmt(leftDx)} ${fmt(leftDy)})`),
    handPose
  )}`;
  elems.leftArm?.setAttribute("transform", leftArmTransform);
  elems.leftArmGuide.setAttribute("transform", leftArmTransform);

  const footSettle = Math.sin(TAU * oldTypingPhase + Math.PI / 6) * breathAmp * 0.035;
  elems.leftFoot.setAttribute("transform", withPartTransform("leftFoot", `translate(0 ${fmt(footSettle)})`));
  elems.rightFoot.setAttribute("transform", withPartTransform("rightFoot", `translate(0 ${fmt(-footSettle * .6)})`));
  elems.leftFootGuide.setAttribute("transform", `${patchTransform} ${elems.leftFoot.getAttribute("transform")}`);
  elems.rightFootGuide.setAttribute("transform", `${patchTransform} ${elems.rightFoot.getAttribute("transform")}`);

  elems.laptopMapped.setAttribute(
    "transform",
    `translate(${fmt(num("laptopX"))} ${fmt(num("laptopY"))}) scale(${fmt(num("laptopScale"))})`
  );
  elems.laptop.removeAttribute("transform");
  elems.keyboardTap?.setAttribute("opacity", fmt(0.08 + rightBeat * 0.42));
  renderAtmosphere(now);
  elems.sourceGhost.classList.toggle("is-hidden", !controls.showFullSource.checked);
  elems.stage.classList.toggle("checker", controls.showChecker.checked);
  elems.clipGuides.classList.toggle("is-hidden", !controls.showClipGuides.checked);
  elems.handPivotGuides.classList.toggle("is-hidden", !controls.showClipGuides.checked);
  elems.laptopMapped.classList.toggle("is-hidden", !controls.showLaptop.checked);
  syncHandGuides(leftArmTransform, `${patchTransform} ${rightArmTransform}`);
  toggleOriginalLimbs();
  syncPartButtons();
  syncOutputs(handPose, now);

  if (previewingHands || controls.playing.checked || previewingHead) scheduleRender();
}

function renderAtmosphere(now = 0) {
  if (!elems.atmosphere) return;
  const enabled = controls.showAtmosphere.checked;
  elems.atmosphere.classList.toggle("is-hidden", !enabled);
  if (!enabled) return;

  const glowPower = num("glowPower");
  const liveMotion = previewingHands || previewingHead || controls.playing.checked;
  const cycle = liveMotion ? phase : ((now || 0) / HEAD_SYNC_DURATION) % 1;
  const pulse = 0.94 + 0.06 * Math.sin(TAU * (cycle * 1.15 + 0.08));
  const screenLook = smoothRange(45, 70, headLook.pitch);
  const lookSoften = 1 - lookPersonAmount() * 0.18;
  const glow = glowPower * pulse * lookSoften * lerp(0.72, 1, screenLook);

  elems.atmosphere.setAttribute("opacity", fmt(enabled ? 1 : 0));
  elems.screenGlow?.setAttribute("opacity", fmt(clamp(glowPower, 0, 1.4)));
  elems.screenGlowBeam?.setAttribute(
    "transform",
    `translate(${fmt(Math.sin(TAU * cycle) * 1.4)} ${fmt(Math.cos(TAU * cycle) * -1.1)}) scale(${fmt(1 + glow * .018)})`
  );
  elems.screenGlowBeam?.setAttribute("opacity", fmt(0.20 + glow * 0.20));
  elems.screenGlowHalo?.setAttribute(
    "transform",
    `translate(${fmt(Math.sin(TAU * (cycle + .16)) * 2.1)} ${fmt(Math.cos(TAU * cycle) * -1.4)}) scale(${fmt(1 + glow * .025)})`
  );
  elems.screenGlowHalo?.setAttribute("opacity", fmt(0.32 + glow * 0.34));
  elems.faceGlowWash?.setAttribute("opacity", fmt(0.025 + glow * 0.04));
  elems.screenEdgeGlow?.setAttribute("opacity", fmt(0.22 + glow * 0.28));
}

function applyBodyShape() {
  if (!baseSvg) return;
  const bodyPath = baseSvg.querySelector("#body-belly-fill");
  if (!bodyPath) return;
  const bulge = num("bodyBackBulge");
  if (Math.abs(bulge) < 0.01) {
    bodyPath.setAttribute("d", BODY_BASE_D);
    return;
  }

  const lowerCtrlX = 303.48 + bulge * 0.45;
  const midX = 303.48 + bulge * 0.85;
  const upperCtrlX = 303.48 + bulge * 1.05;
  const shoulderCtrlX = 254.13 + bulge * 0.35;
  bodyPath.setAttribute(
    "d",
    `M163.75 200 C100.24 200 54.75 251 54.75 322 C54.75 375.7 99.08 412 170.72 412 C269.61 412 ${fmt(lowerCtrlX)} 385.22 ${fmt(midX)} 322 C ${fmt(upperCtrlX)} 244.61 ${fmt(shoulderCtrlX)} 200 163.75 200Z`
  );
}

function renderHeadLook(now = 0) {
  if (!baseSvg) return;
  headLook = renderedHeadPose(now);
  const lookActive = headLookActive();
  const cheek = cheekPath();
  const elem = elementOffsets();
  const ears = earState();

  setAttr("head-cap-fill", "d", headCapPath());
  setAttr("cheek-muzzle-fill", "d", cheek);
  setAttr("idle-look-blush-clip-path", "d", cheek);
  setAttr("left-cheek-crease", "d", creasePath("left"));
  setAttr("right-cheek-crease", "d", creasePath("right"));
  setAttr("left-cheek-crease", "stroke-width", lookActive ? "2.6" : "3");
  setAttr("right-cheek-crease", "stroke-width", lookActive ? "2.6" : "3");

  setLayerTransform("head-layer", "");
  setLayerTransform("face-layer", lookActive ? facePlaneTransform(true) : "");
  setLayerTransform("idle-look-blush-clip-wrapper", "");
  setElementTransform("idle-look-blush-transform", lookActive ? blushPlaneTransform() : "");
  setLayerTransform("ears-layer", "");
  setLayerTransform("head-tufts", lookActive ? tuftLookTransform() : "");

  setAttr("left-ear", "transform", lookActive ? translate(ears.left.x, ears.left.y) : "");
  setAttr("right-ear", "transform", lookActive ? translate(ears.right.x, ears.right.y) : "");
  setAttr("left-ear-outer", "r", fmt(lerp(34, 37.4, ears.left.grow)));
  setAttr("left-ear-inner", "r", fmt(lerp(18, 19.8, ears.left.grow)));
  setAttr("right-ear-outer", "r", fmt(lerp(34, 37.4, ears.right.grow)));
  setAttr("right-ear-inner", "r", fmt(lerp(18, 19.8, ears.right.grow)));

  const blink = blinkAmount();
  setAttr("left-eye", "rx", fmt(lerp(12.5, 13.6, blink)));
  setAttr("right-eye", "rx", fmt(lerp(12.5, 13.6, blink)));
  setAttr("left-eye", "ry", fmt(lerp(17, 1.4, blink)));
  setAttr("right-eye", "ry", fmt(lerp(17, 1.4, blink)));
  setAttr("left-eye", "transform", centeredTransform({ x: 138, y: 157 }, elem.leftEye.dx, elem.leftEye.dy));
  setAttr("right-eye", "transform", centeredTransform({ x: 237, y: 157 }, elem.rightEye.dx, elem.rightEye.dy));
  const browLift = lookPersonAmount();
  setAttr("left-brow", "transform", browTransform({ x: 140, y: 116 }, browLift, -2.5));
  setAttr("right-brow", "transform", browTransform({ x: 234, y: 116 }, browLift, 2.5));
  setAttr("left-blush", "transform", centeredTransform({ x: 92, y: 185 }, elem.leftBlush.dx, elem.leftBlush.dy, elem.leftBlush.sx, elem.leftBlush.sy));
  setAttr("right-blush", "transform", centeredTransform({ x: 281, y: 185 }, elem.rightBlush.dx, elem.rightBlush.dy, elem.rightBlush.sx, elem.rightBlush.sy));
  applySunglassesPerformance();
  setAttr("nose-mouth", "transform", "");
}

function setAttr(id, name, value) {
  const node = baseSvg?.querySelector(`#${id}`);
  if (!node) return;
  if (value === null || value === undefined || value === "") node.removeAttribute(name);
  else node.setAttribute(name, value);
}

function setLayerTransform(id, value) {
  setAttr(id, "transform", value);
}

function setElementTransform(id, value) {
  setAttr(id, "transform", value);
}

function headLookActive() {
  return Math.abs(headLook.yaw) > .001 || Math.abs(headLook.pitch) > .001;
}

function axisT(value) {
  return smooth01(Math.abs(value) / 100);
}

function diagonalFactor() {
  return Math.abs(headLook.yaw) / 100 * Math.abs(headLook.pitch) / 100;
}

function trimmed(value, trimScale = 1) {
  const trim = 1 - diagonalFactor() * 15 / 100 * trimScale;
  return value * trim;
}

function smoothRange(start, end, value) {
  return smooth01(clamp((value - start) / (end - start), 0, 1));
}

function mixPoint(a, b, t) {
  return { x: lerp(a.x, b.x, t), y: lerp(a.y, b.y, t) };
}

function interpolateNumberString(from, to, t) {
  const a = numbers(from);
  const b = numbers(to);
  let index = 0;
  if (!from || !to || a.length !== b.length) return t < 1 ? from : to;
  return from.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => fmt(lerp(a[index], b[index++] ?? a[index - 1], t)));
}

function transformTopPoint(point, dir) {
  const axisX = dir < 0 ? 125 : 249;
  const axisTravel = (axisX - VIEW_W / 2) * .75;
  const localX = point.x - axisX;
  const next = { x: axisTravel + axisX + localX, y: point.y };
  const a = rawAnchors.A || { x: 65 };
  const g = rawAnchors.G || { x: 309 };
  const weightT = clamp((point.x - a.x) / (g.x - a.x), 0, 1);
  const weight = Math.pow(Math.sin(Math.PI * weightT), .9);
  return {
    x: point.x + (next.x - point.x) * weight,
    y: point.y
  };
}

function catmullPath(points, tension = .72, sharpness = .34) {
  const segs = [`M${fmt(points[0].x)} ${fmt(points[0].y)}`];
  for (let i = 0; i < points.length - 1; i += 1) {
    const p0 = points[Math.max(0, i - 1)];
    const p1 = points[i];
    const p2 = points[i + 1];
    const p3 = points[Math.min(points.length - 1, i + 2)];
    const nearBridge = ["C", "D", "E"].includes(p1.id) || ["C", "D", "E"].includes(p2.id);
    const localTension = tension * (nearBridge ? (1 - sharpness * .42) : 1);
    const c1 = {
      x: p1.x + (p2.x - p0.x) * localTension / 6,
      y: p1.y + (p2.y - p0.y) * localTension / 6
    };
    const c2 = {
      x: p2.x - (p3.x - p1.x) * localTension / 6,
      y: p2.y - (p3.y - p1.y) * localTension / 6
    };
    segs.push(`C${fmt(c1.x)} ${fmt(c1.y)} ${fmt(c2.x)} ${fmt(c2.y)} ${fmt(p2.x)} ${fmt(p2.y)}`);
  }
  return segs.join(" ");
}

function yawFacePath() {
  const dir = Math.sign(headLook.yaw);
  const t = axisT(headLook.yaw);
  if (!dir || t <= .001 || TOP_CHAIN.some((id) => !rawAnchors[id])) return BASE_HEAD.cheekD;
  const top = TOP_CHAIN.map((id) => {
    const start = rawAnchors[id];
    const end = transformTopPoint(start, dir);
    return { id, ...mixPoint(start, end, t) };
  });
  const sideTail = dir < 0 ? LEFT_TAIL : RIGHT_TAIL;
  const tail = FRONT_TAIL.map((seg, index) => {
    const mixed = seg.map((value, numberIndex) => lerp(value, sideTail[index][numberIndex], t));
    return `C${fmt(mixed[0])} ${fmt(mixed[1])} ${fmt(mixed[2])} ${fmt(mixed[3])} ${fmt(mixed[4])} ${fmt(mixed[5])}`;
  }).join(" ");
  return `${catmullPath(top)} ${tail}Z`;
}

function faceLowerEffect() {
  if (headLook.pitch <= 0) return 0;
  return axisT(headLook.pitch) * lerp(.45, 1, axisT(headLook.yaw));
}

function faceLowerWrappedPoint(point) {
  const effect = faceLowerEffect();
  if (effect <= .001) return point;
  const lower = smoothRange(238, 263, point.y);
  if (lower <= .001) return point;
  const side = Math.sign(point.x - 187);
  return {
    x: point.x + side * 6 * effect * lower * .3,
    y: point.y + 12 * effect * lower
  };
}

function faceLowerWrappedPath(path) {
  return transformPathPairs(path, faceLowerWrappedPoint);
}

function pitchDeltaY(y) {
  if (headLook.pitch === 0) return 0;
  const sign = Math.sign(headLook.pitch);
  const t = axisT(headLook.pitch);
  const lowerWeight = clamp((y - 166) / 92, 0, 1);
  if (sign < 0) return lerp(PITCH_UP.axis, PITCH_UP.lower, lowerWeight) * t;
  return lerp(PITCH_DOWN.axis, PITCH_DOWN.lower, lowerWeight) * t;
}

function warpPathForPitch(path) {
  let index = 0;
  return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, (value) => {
    const n = Number(value);
    const next = index % 2 === 1 ? n + pitchDeltaY(n) : n;
    index += 1;
    return fmt(next);
  });
}

function cheekPath() {
  return faceLowerWrappedPath(warpPathForPitch(yawFacePath()));
}

function headCapPath() {
  const yawT = axisT(headLook.yaw);
  const dir = Math.sign(headLook.yaw);
  const yawTarget = dir > 0 ? RIGHT_HEAD_CAP_D : LEFT_HEAD_CAP_D;
  const yawPath = dir ? interpolateNumberString(BASE_HEAD.headCapD, yawTarget, yawT) : BASE_HEAD.headCapD;
  let index = 0;
  return yawPath.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, (value) => {
    const n = Number(value);
    if (index % 2 === 0) {
      index += 1;
      return fmt(n);
    }
    const topWeight = clamp((120 - n) / 80, 0, 1);
    const sideWeight = clamp((n - 120) / 70, 0, 1);
    const sign = Math.sign(headLook.pitch);
    const t = axisT(headLook.pitch);
    const delta = sign < 0
      ? (2 * topWeight - 5.61 * sideWeight) * t
      : (-1.87 * topWeight + 7.28 * sideWeight) * t;
    index += 1;
    return fmt(n + delta);
  });
}

function creasePath(side) {
  const isLeft = side === "left";
  const base = BASE_HEAD[isLeft ? "leftCreaseD" : "rightCreaseD"];
  const sideSign = isLeft ? 1 : -1;
  const startX = isLeft ? 62 : 312;
  const baseLength = 38;
  const yawT = axisT(headLook.yaw);
  const yawPull = Math.sign(headLook.yaw) * yawT;
  const pitchT = axisT(headLook.pitch);
  return transformPathPairs(base, (point) => {
    const along = isLeft
      ? clamp((point.x - 62) / baseLength, 0, 1)
      : clamp((312 - point.x) / baseLength, 0, 1);
    let next = {
      x: startX + (point.x - startX),
      y: point.y
    };
    next.x += yawPull * (isLeft ? 1 : -1) * lerp(3, 6, along);
    next.x += sideSign * lerp(1.8, 2.4, along) * pitchT;
    next.y += pitchDeltaY(point.y);
    return faceLowerWrappedPoint(next);
  });
}

function facePlaneTransform(withPitchScale) {
  const dir = Math.sign(headLook.yaw);
  const yawT = axisT(headLook.yaw);
  const axis = 187 + dir * 62 * yawT;
  const dx = dir * 46.5 * yawT;
  const pitchSign = Math.sign(headLook.pitch);
  const pitchT = axisT(headLook.pitch);
  const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
  const dy = trimmed(pitchData.faceDy * pitchT, .45);
  const sy = withPitchScale ? lerp(1, pitchData.faceSy, pitchT) : 1;
  return `translate(${fmt(dx)} ${fmt(dy)}) translate(${fmt(axis)} 172) skewX(0) scale(1 ${fmt(sy)}) translate(${fmt(-axis)} -172)`;
}

function blushPlaneTransform() {
  const dir = Math.sign(headLook.yaw);
  const yawT = axisT(headLook.yaw);
  const axis = 187 + dir * 62 * yawT;
  const dx = dir * 46.5 * yawT;
  const pitchSign = Math.sign(headLook.pitch);
  const pitchT = axisT(headLook.pitch);
  const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
  const dy = trimmed(pitchData.blushDy * pitchT, .35);
  return `translate(${fmt(dx)} ${fmt(dy)}) translate(${fmt(axis)} 172) skewX(0) scale(1 1) translate(${fmt(-axis)} -172)`;
}

function centeredTransform(origin, dx, dy, sx = 1, sy = 1) {
  if (Math.abs(dx) < 1e-6 && Math.abs(dy) < 1e-6 && Math.abs(sx - 1) < 1e-6 && Math.abs(sy - 1) < 1e-6) return "";
  return `translate(${fmt(origin.x + dx)} ${fmt(origin.y + dy)}) scale(${fmt(sx)} ${fmt(sy)}) translate(${fmt(-origin.x)} ${fmt(-origin.y)})`;
}

function elementOffsets() {
  const dir = Math.sign(headLook.yaw);
  const yawT = axisT(headLook.yaw);
  const pitchSign = Math.sign(headLook.pitch);
  const pitchT = axisT(headLook.pitch);
  const pitchUp = pitchSign < 0;
  const pitchEye = pitchUp ? -.56 * pitchT : 0;
  const pitchBlushDx = pitchUp ? 3.5 * pitchT : -1.8 * pitchT;
  const yawLeftEye = dir < 0 ? -2 * yawT : 0;
  const yawRightEye = dir > 0 ? 2 * yawT : 0;
  const leftBlushYaw = dir < 0
    ? { dx: 6.5 * yawT, dy: 0, sx: 1, sy: 1 }
    : { dx: -24 * yawT, dy: 20.5 * yawT, sx: lerp(1, 1.09, yawT), sy: lerp(1, 1.1, yawT) };
  const rightBlushYaw = dir < 0
    ? { dx: 25 * yawT, dy: 20.5 * yawT, sx: lerp(1, 1.09, yawT), sy: lerp(1, 1.1, yawT) }
    : { dx: -5.5 * yawT, dy: 0, sx: 1, sy: 1 };
  return {
    leftEye: { dx: yawLeftEye, dy: pitchEye },
    rightEye: { dx: yawRightEye, dy: pitchEye },
    leftBlush: {
      dx: leftBlushYaw.dx + pitchBlushDx,
      dy: leftBlushYaw.dy,
      sx: leftBlushYaw.sx,
      sy: leftBlushYaw.sy
    },
    rightBlush: {
      dx: rightBlushYaw.dx - pitchBlushDx,
      dy: rightBlushYaw.dy,
      sx: rightBlushYaw.sx,
      sy: rightBlushYaw.sy
    }
  };
}

function earState() {
  const dir = Math.sign(headLook.yaw);
  const yawT = axisT(headLook.yaw);
  const pitchSign = Math.sign(headLook.pitch);
  const pitchT = axisT(headLook.pitch);
  const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
  const pitchDy = pitchData.earDy * pitchT;
  const left = { x: 0, y: pitchDy, grow: 0 };
  const right = { x: 0, y: pitchDy, grow: 0 };
  if (dir < 0) {
    left.x += -3.5 * yawT;
    left.y += 3.5 * yawT;
    right.grow = smoothRange(.12, 1, yawT);
  } else if (dir > 0) {
    right.x += -9.5 * yawT;
    right.y += 3.5 * yawT;
    left.grow = smoothRange(.12, 1, yawT);
  }
  return { left, right };
}

function tuftLookTransform() {
  const dir = Math.sign(headLook.yaw);
  const yawT = axisT(headLook.yaw);
  const pitchSign = Math.sign(headLook.pitch);
  const pitchT = axisT(headLook.pitch);
  const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
  const yawDx = dir < 0 ? -21.7 * yawT : dir > 0 ? -10.3 * yawT : 0;
  const pitchDy = pitchData.tuftDy * pitchT;
  return translate(yawDx, pitchDy);
}

function translate(x, y) {
  return Math.abs(x) < 1e-6 && Math.abs(y) < 1e-6 ? "" : `translate(${fmt(x)} ${fmt(y)})`;
}

function transformPathPairs(path, fn) {
  const values = numbers(path);
  const output = [];
  for (let i = 0; i < values.length; i += 2) {
    const point = fn({ x: values[i], y: values[i + 1] });
    output.push(point.x, point.y);
  }
  let index = 0;
  return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => fmt(output[index++]));
}

function headPreviewProgress(now) {
  if (!previewingHead) return 0;
  return ((now - headPreviewStart) % HEAD_SYNC_DURATION) / HEAD_SYNC_DURATION;
}

function handsSlowForHead(now) {
  if (!previewingHands || !previewingHead) return false;
  const progress = headPreviewProgress(now);
  return progress >= HEAD_LOOK_PERSON_HOLD.start && progress <= HEAD_LOOK_PERSON_HOLD.end;
}

function handCycleMs(now) {
  return Math.max(1, num(handsSlowForHead(now) ? "handLookMs" : "handPreviewMs"));
}

function renderedHeadPose(now) {
  if (!previewingHead) {
    headPreviewMeta = { from: activeHeadKey, to: activeHeadKey, local: 0, progress: 0 };
    return headKeyframes[activeHeadKey];
  }
  const progress = headPreviewProgress(now);
  const stops = [
    { at: 0, key: "start" },
    { at: 0.18, key: "middle" },
    { at: 0.34, key: "start" },
    { at: 0.50, key: "middle" },
    { at: 0.66, key: "end" },
    { at: 0.86, key: "end" },
    { at: 1, key: "start" }
  ];
  for (let i = 0; i < stops.length - 1; i += 1) {
    const a = stops[i];
    const b = stops[i + 1];
    if (progress >= a.at && progress <= b.at) {
      const local = smooth01((progress - a.at) / (b.at - a.at));
      headPreviewMeta = { from: a.key, to: b.key, local, progress };
      return interpolateHeadPose(headKeyframes[a.key], headKeyframes[b.key], local);
    }
  }
  headPreviewMeta = { from: "start", to: "start", local: 0, progress };
  return headKeyframes.start;
}

function interpolateHeadPose(a, b, t) {
  return {
    yaw: lerp(a.yaw, b.yaw, t),
    pitch: lerp(a.pitch, b.pitch, t),
    angle: lerp(a.angle, b.angle, t)
  };
}

function blinkAmount() {
  if (!previewingHead || headPreviewMeta.from !== "end" || headPreviewMeta.to !== "end") return 0;
  return Math.max(
    blinkPulse(headPreviewMeta.local, 0.22, 0.11),
    blinkPulse(headPreviewMeta.local, 0.56, 0.10)
  );
}

function lookPersonAmount() {
  const end = headKeyframes.end;
  const screenPitch = headKeyframes.start.pitch;
  const pitchRange = screenPitch - end.pitch || 1;
  const pitchT = 1 - clamp((headLook.pitch - end.pitch) / pitchRange, 0, 1);
  const yawT = 1 - clamp(Math.abs(headLook.yaw - end.yaw) / 32, 0, 1);
  return smooth01(clamp(pitchT * yawT, 0, 1));
}

function browTransform(origin, amount, angle) {
  if (amount <= .001) return "";
  const dy = -2.3 * amount;
  return `translate(${fmt(origin.x)} ${fmt(origin.y + dy)}) rotate(${fmt(angle * amount)}) translate(${fmt(-origin.x)} ${fmt(-origin.y)})`;
}

function blinkPulse(t, center, width) {
  return smooth01(clamp(1 - Math.abs(t - center) / width, 0, 1));
}

function applySunglassesPerformance() {
  const screenLook = smoothRange(54, 68, headLook.pitch);
  const screenLeft = headKeyframes.start.yaw;
  const screenRight = headKeyframes.middle.yaw;
  const scanT = clamp((headLook.yaw - screenLeft) / (screenRight - screenLeft || 1), 0, 1);
  const shineDx = lerp(-3.8, 4.2, scanT) * screenLook;
  const shineDy = lerp(0.8, -0.35, scanT) * screenLook;
  const shineTransform = translate(shineDx, shineDy);
  const shimmer = screenLook * (0.55 + 0.45 * Math.sin(scanT * Math.PI));
  const mainOpacity = fmt(0.10 + shimmer * 0.07);
  const smallOpacity = fmt(0.07 + shimmer * 0.05);

  [
    "left-lens-main-shine",
    "right-lens-main-shine"
  ].forEach((id) => {
    setAttr(id, "transform", shineTransform);
    setAttr(id, "opacity", mainOpacity);
  });
  [
    "left-lens-small-shine",
    "right-lens-small-shine"
  ].forEach((id) => {
    setAttr(id, "transform", shineTransform);
    setAttr(id, "opacity", smallOpacity);
  });
}

function stopHeadPreview() {
  previewingHead = false;
  syncHeadButtons();
}

function withPartTransform(part, baseTransform) {
  const transform = partTransforms[part];
  const pivot = PART_META[part].pivot;
  const manual = `translate(${fmt(pivot.x)} ${fmt(pivot.y)}) rotate(${fmt(transform.rotate)}) scale(${fmt(transform.scale)}) translate(-${fmt(pivot.x)} -${fmt(pivot.y)}) translate(${fmt(transform.x)} ${fmt(transform.y)})`;
  return `${baseTransform} ${manual}`;
}

function withHandRotation(side, baseTransform, pose = renderedHandPose()) {
  const pivot = pose[side];
  const angle = pivot.angle;
  const rotation = `translate(${fmt(pivot.x)} ${fmt(pivot.y)}) rotate(${fmt(angle)}) translate(-${fmt(pivot.x)} -${fmt(pivot.y)})`;
  return `${baseTransform} ${rotation}`;
}

function syncOutputs() {}


function syncHandOutputs() {}


function updatePivotGuide() {}


function syncHandGuides() {}


function resetHandRotationControls() {
  applyHandPose(HAND_ROTATION_DEFAULTS, false);
}

function applyHandPose(pose, renderAfter = true) {
  controls.playing.checked = false;
  previewingHands = false;
  previewingHead = false;
  syncHandPreviewButton();
  syncHeadButtons();
  controls.phase.value = 0;
  phase = 0;
  setHandControlsFromPose(pose);
  syncHandOutputs();
  if (renderAfter) scheduleRender();
}

function setHandControlsFromPose(pose) {
  handControls.leftHandAngle.value = pose.left.angle;
  handControls.leftPivotX.value = pose.left.pivotX;
  handControls.leftPivotY.value = pose.left.pivotY;
  handControls.rightHandAngle.value = pose.right.angle;
  handControls.rightPivotX.value = pose.right.pivotX;
  handControls.rightPivotY.value = pose.right.pivotY;
}

function readHandPoseFromControls() {
  return {
    left: {
      angle: handNum("leftHandAngle"),
      x: handNum("leftPivotX"),
      y: handNum("leftPivotY")
    },
    right: {
      angle: handNum("rightHandAngle"),
      x: handNum("rightPivotX"),
      y: handNum("rightPivotY")
    }
  };
}

function renderedHandPose() {
  if (!previewingHands) return readHandPoseFromControls();
  const t = smooth01((1 - Math.cos(TAU * phase)) / 2);
  return mixHandPose(HAND_TYPING_POSES.a, HAND_TYPING_POSES.b, t);
}

function mixHandPose(from, to, t) {
  return {
    left: mixHandSide(from.left, to.left, t),
    right: mixHandSide(from.right, to.right, t)
  };
}

function mixHandSide(from, to, t) {
  return {
    angle: lerp(from.angle, to.angle, t),
    x: lerp(from.pivotX, to.pivotX, t),
    y: lerp(from.pivotY, to.pivotY, t)
  };
}

