function writeActiveHeadKeyFromControls() {}


function syncHeadButtons() {}


function headKeyText(key) {
  const yawText = key.yaw < 0 ? `左 ${fmt(Math.abs(key.yaw))}%` : key.yaw > 0 ? `右 ${fmt(key.yaw)}%` : "中";
  const pitchText = key.pitch < 0 ? `上 ${fmt(Math.abs(key.pitch))}%` : key.pitch > 0 ? `下 ${fmt(key.pitch)}%` : "中";
  return `${yawText} / ${pitchText} / 角度 ${fmt(key.angle)}deg`;
}

function syncPartControls() {}


function syncPartButtons() {}


function syncPartOutputs() {}


function loadPartTransforms() {
  try {
    const parsed = JSON.parse(localStorage.getItem(PART_STORAGE_KEY));
    if (parsed) return normalizePartTransforms(parsed);
  } catch {}
  return normalizePartTransforms(PART_DEFAULTS);
}

function normalizePartTransforms(input) {
  const normalized = {};
  for (const key of Object.keys(PART_DEFAULTS)) {
    const source = input?.[key] || {};
    normalized[key] = {
      x: Number.isFinite(Number(source.x)) ? Number(source.x) : PART_DEFAULTS[key].x,
      y: Number.isFinite(Number(source.y)) ? Number(source.y) : PART_DEFAULTS[key].y,
      scale: Number.isFinite(Number(source.scale)) ? Number(source.scale) : PART_DEFAULTS[key].scale,
      rotate: Number.isFinite(Number(source.rotate)) ? Number(source.rotate) : PART_DEFAULTS[key].rotate
    };
  }
  return normalized;
}

function persistPartTransforms() {}


function num(id) {
  return Number(controls[id].value);
}

function handNum(id) {
  return Number(handControls[id].value);
}

function numbers(value) {
  return (value.match(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi) || []).map(Number);
}

function smooth01(value) {
  const t = clamp(value, 0, 1);
  return t * t * (3 - 2 * t);
}

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function lerp(a, b, t) {
  return a + (b - a) * t;
}

function fmt(n) {
  return String(Number(Number(n).toFixed(3)));
}

function easePulse(t) {
  const clamped = Math.max(0, Math.min(1, t));
  return clamped * clamped * (3 - 2 * clamped);
}

function escapeHtml(text) {
  return String(text).replace(/[&<>"']/g, (ch) => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    '"': "&quot;",
    "'": "&#39;"
  }[ch]));
}
